#!/usr/bin/env python3
"""Mesh Lifecycle and Topology CLI Tool"""

import argparse
import json
import os
import sys
from dataclasses import dataclass, field
from enum import Enum
from pathlib import Path
from typing import Any, Dict, List, Optional

import yaml


# Data Storage (in-memory for this implementation)
_MESHES: Dict[str, Dict] = {}


class ErrorType(Enum):
    NOT_FOUND = "not_found"
    IMMUTABLE = "immutable"
    INVALID = "invalid"


@dataclass
class ValidationError:
    field: str
    type: str
    message: str

    def to_dict(self) -> Dict[str, str]:
        return {
            "field": self.field,
            "type": self.type,
            "message": self.message,
        }


@dataclass
class Condition:
    type: str
    status: str  # "True" or "False"
    message: str = ""

    def to_dict(self) -> Dict[str, str]:
        return {
            "type": self.type,
            "status": self.status,
            "message": self.message,
        }


@dataclass
class Storage:
    size: Optional[str] = None  # Default is "1Gi"
    ephemeral: bool = False
    className: Optional[str] = None

    def __post_init__(self):
        if self.size is None:
            self.size = "1Gi"

    def to_dict(self) -> Dict[str, Any]:
        result = {"ephemeral": self.ephemeral}
        if self.ephemeral:
            return {"ephemeral": True}
        result["size"] = self.size
        return result


@dataclass
class Network:
    storage: Optional[Storage] = None
    replicationFactor: Optional[int] = None

    def __post_init__(self):
        if self.storage is None:
            self.storage = Storage()

    def to_dict(self) -> Dict[str, Any]:
        result = {}
        if self.storage:
            result["storage"] = self.storage.to_dict()
        if self.replicationFactor is not None:
            result["replicationFactor"] = self.replicationFactor
        return result


@dataclass
class Spec:
    instances: int = 1
    network: Optional[Network] = None

    def __post_init__(self):
        if self.network is None:
            self.network = Network()
        if self.network.storage is None:
            self.network.storage = Storage()

    def to_dict(self) -> Dict[str, Any]:
        result = {"instances": self.instances}
        if self.network:
            result["network"] = self.network.to_dict()
        return result


@dataclass
class StatusInstances:
    ready: int = 0
    starting: int = 0
    stopped: int = 0

    def to_dict(self) -> Dict[str, int]:
        return {
            "ready": self.ready,
            "starting": self.starting,
            "stopped": self.stopping if hasattr(self, 'stopped') else 0,
        }


@dataclass
class Status:
    state: str = "Stopped"  # "Running" or "Stopped"
    stable: bool = True
    instances: Optional[StatusInstances] = None
    desiredInstancesOnResume: Optional[int] = None
    conditions: List[Condition] = field(default_factory=list)

    def __post_init__(self):
        if self.instances is None:
            self.instances = StatusInstances()

    def to_dict(self) -> Dict[str, Any]:
        result = {
            "state": self.state,
            "stable": self.stable,
        }
        if self.instances:
            result["instances"] = self.instances.to_dict()
        if self.desiredInstancesOnResume is not None:
            result["desiredInstancesOnResume"] = self.desiredInstancesOnResume
        if self.conditions:
            sorted_conditions = sorted(self.conditions, key=lambda c: c.type)
            result["conditions"] = [c.to_dict() for c in sorted_conditions]
        return result


@dataclass
class Mesh:
    apiVersion: str = "mesh.example.com/v1"
    kind: str = "Mesh"
    metadata: Optional[Dict] = None
    spec: Optional[Spec] = None
    status: Optional[Status] = None

    def __post_init__(self):
        if self.metadata is None:
            self.metadata = {}
        if self.spec is None:
            self.spec = Spec()
        if self.status is None:
            self.status = Status()


def parse_yaml_file(path: str) -> Dict:
    """Parse a YAML file and return the data."""
    file_path = Path(path)
    if not file_path.exists():
        raise FileNotFoundError(f"File not found: {path}")

    with open(file_path, 'r') as f:
        data = yaml.safe_load(f)
        if data is None:
            raise ValueError(f"Empty YAML file: {path}")
        return data


def validate_mesh_name(name: str, context: str) -> List[ValidationError]:
    """Validate mesh name."""
    errors = []
    if not name or not isinstance(name, str):
        errors.append(ValidationError(
            field="metadata.name",
            type=ErrorType.INVALID.value,
            message=f"Invalid name: {name}"
        ))
    return errors


def validate_instances(instances: Any, context: str) -> List[ValidationError]:
    """Validate instances field."""
    errors = []
    if instances is None:
        return errors
    if not isinstance(instances, int):
        errors.append(ValidationError(
            field="spec.instances",
            type=ErrorType.INVALID.value,
            message=f"instances must be an integer, got {type(instances).__name__}"
        ))
    elif instances < 0:
        errors.append(ValidationError(
            field="spec.instances",
            type=ErrorType.INVALID.value,
            message=f"instances must be non-negative, got {instances}"
        ))
    return errors


def validate_storage_size(size: Any, context: str) -> List[ValidationError]:
    """Validate storage size field."""
    errors = []
    if not isinstance(size, str):
        errors.append(ValidationError(
            field="spec.network.storage.size",
            type=ErrorType.INVALID.value,
            message=f"size must be a string, got {type(size).__name__}"
        ))
        return errors

    # Parse memory quantity format
    size_str = size.strip().lower()

    # Check if it's just a number
    if size_str.isdigit():
        int(size_str)  # Will raise if invalid
        return errors

    # Check format: number followed by unit
    import re
    match = re.match(r'^(\d+)(Ki|Mi|Gi|Ti)$', size_str)
    if match:
        return errors

    errors.append(ValidationError(
        field="spec.network.storage.size",
        type=ErrorType.INVALID.value,
        message=f"size must be a non-negative integer or use Ki/Mi/Gi/Ti units, got '{size}'"
    ))
    return errors


def validate_replication_factor(rf: Any, instances: int, context: str) -> List[ValidationError]:
    """Validate replication factor against instances."""
    errors = []
    if rf is None:
        return errors

    if not isinstance(rf, int):
        errors.append(ValidationError(
            field="spec.network.replicationFactor",
            type=ErrorType.INVALID.value,
            message=f"replicationFactor must be an integer, got {type(rf).__name__}"
        ))
        return errors

    if rf < 1:
        errors.append(ValidationError(
            field="spec.network.replicationFactor",
            type=ErrorType.INVALID.value,
            message=f"replicationFactor must be at least 1, got {rf}"
        ))

    if instances > 0 and rf > instances:
        errors.append(ValidationError(
            field="spec.network.replicationFactor",
            type=ErrorType.INVALID.value,
            message=f"replicationFactor ({rf}) cannot exceed instances ({instances})"
        ))

    return errors


def compute_replication_factor_default(instances: int) -> int:
    """Compute default replication factor based on instances."""
    if instances <= 0:
        return 1
    return min(3, instances)


def validate_mesh_on_create(data: Dict) -> List[ValidationError]:
    """Validate mesh data on creation."""
    errors = []

    # Validate metadata.name
    name = data.get("metadata", {}).get("name")
    if not name or not isinstance(name, str):
        errors.append(ValidationError(
            field="metadata.name",
            type=ErrorType.INVALID.value,
            message="metadata.name is required and must be a non-empty string"
        ))

    # Validate spec.instances
    instances = data.get("spec", {}).get("instances")
    errors.extend(validate_instances(instances, "create"))

    # Validate spec.network.storage.size
    storage = data.get("spec", {}).get("network", {}).get("storage", {})
    size = storage.get("size")
    if size is not None:
        errors.extend(validate_storage_size(size, "create"))

    # Validate replication factor
    rf = data.get("spec", {}).get("network", {}).get("replicationFactor")
    instance_count = instances if isinstance(instances, int) else 0
    errors.extend(validate_replication_factor(rf, instance_count, "create"))

    return errors


def validate_mesh_on_update(existing: Dict, new: Dict) -> List[ValidationError]:
    """Validate mesh update."""
    errors = []

    # Check for immutable field changes
    existing_storage = existing.get("spec", {}).get("network", {}).get("storage", {})
    new_storage = new.get("spec", {}).get("network", {}).get("storage", {})

    if existing_storage.get("size") is not None and new_storage.get("size") is not None:
        if existing_storage["size"] != new_storage["size"]:
            errors.append(ValidationError(
                field="spec.network.storage.size",
                type=ErrorType.IMMUTABLE.value,
                message=f"field 'spec.network.storage.size' is immutable after creation"
            ))

    # Validate instances
    new_instances = new.get("spec", {}).get("instances")
    errors.extend(validate_instances(new_instances, "update"))

    # Validate replication factor
    new_rf = new.get("spec", {}).get("network", {}).get("replicationFactor")
    existing_instances = existing.get("spec", {}).get("instances", 0)
    instance_count = new_instances if isinstance(new_instances, int) else existing_instances
    errors.extend(validate_replication_factor(new_rf, instance_count, "update"))

    return errors


def merge_storage(existing: Dict, new: Dict) -> Dict:
    """Merge storage configuration."""
    result = existing.copy()

    new_storage = new.get("storage", {})
    existing_storage = existing.get("storage", {})

    # Merge field by field
    if "ephemeral" in new_storage:
        result["ephemeral"] = new_storage["ephemeral"]
    elif "ephemeral" not in existing:
        result["ephemeral"] = False

    if "className" in new_storage:
        result["className"] = new_storage["className"]
    elif "className" not in existing:
        result["className"] = None

    # size is immutable, keep existing if not in new
    if "size" in new_storage:
        result["size"] = new_storage["size"]
    elif "size" not in existing:
        result["size"] = "1Gi"

    return result


def merge_network(existing: Dict, new: Dict) -> Dict:
    """Merge network configuration."""
    result = existing.copy()

    # Merge storage
    if "storage" in new:
        existing_storage = existing.get("storage", {})
        result["storage"] = merge_storage(existing_storage, new["storage"])

    # Merge replicationFactor (leaf field - replaces)
    if "replicationFactor" in new:
        result["replicationFactor"] = new["replicationFactor"]
    elif "replicationFactor" not in existing:
        # Compute default if not specified
        instances = existing.get("spec", {}).get("instances", 0)
        if "replicationFactor" not in existing and instances > 0:
            result["replicationFactor"] = compute_replication_factor_default(instances)

    return result


def merge_spec(existing: Dict, new: Dict) -> Dict:
    """Merge spec configuration."""
    result = existing.copy()

    # Merge instances (leaf field - replaces)
    if "instances" in new:
        result["instances"] = new["instances"]
    elif "instances" not in existing:
        result["instances"] = 1

    # Merge network
    if "network" in new:
        existing_network = existing.get("network", {})
        result["network"] = merge_network(existing_network, new["network"])

    return result


def merge_mesh(existing: Dict, new: Dict) -> Dict:
    """Merge new mesh configuration into existing mesh."""
    result = existing.copy()

    # Merge spec
    if "spec" in new:
        existing_spec = existing.get("spec", {})
        result["spec"] = merge_spec(existing_spec, new["spec"])

    return result


def handle_instance_lifecycle(mesh: Dict) -> Dict:
    """Handle instance lifecycle transitions and update mesh state."""
    mesh = mesh.copy()
    spec = mesh.get("spec", {})
    status = mesh.get("status", {})

    current_instances = spec.get("instances", 0)
    prev_instances = status.get("instances", {}).get("ready", 0)

    # Handle conditions
    conditions = status.get("conditions", [])

    # Remove transient conditions
    conditions = [c for c in conditions if c.get("type") not in ("Scaling", "GracefulShutdown")]

    new_conditions = []

    if current_instances == 0:
        # Stopped state
        if prev_instances > 0:
            # Scale down to 0 - Stop operation
            conditions.append({
                "type": "GracefulShutdown",
                "status": "True",
                "message": ""
            })
            mesh["status"]["desiredInstancesOnResume"] = prev_instances
            mesh["status"]["instances"] = {
                "ready": 0,
                "starting": 0,
                "stopped": prev_instances
            }
            mesh["status"]["state"] = "Stopped"
            mesh["status"]["stable"] = True
        else:
            # Already stopped
            mesh["status"]["state"] = "Stopped"
            mesh["status"]["stable"] = True

    elif prev_instances == 0 and mesh.get("status", {}).get("desiredInstancesOnResume") is not None:
        # Resume operation
        conditions = [c for c in conditions if c.get("type") != "GracefulShutdown"]

        target_instances = current_instances
        mesh["status"].pop("desiredInstancesOnResume", None)

        mesh["status"]["instances"] = {
            "ready": 0,
            "starting": target_instances,
            "stopped": 0
        }
        mesh["status"]["state"] = "Running"
        mesh["status"]["stable"] = False

        # Add Scaling condition for transient state
        conditions.append({
            "type": "Scaling",
            "status": "True",
            "message": f"Resuming from stopped state to {target_instances} instances"
        })

    elif current_instances != prev_instances:
        # Scale up or down
        if current_instances > prev_instances:
            # Scale up
            conditions.append({
                "type": "Scaling",
                "status": "True",
                "message": f"Scaling from {prev_instances} to {current_instances} instances"
            })
            mesh["status"]["instances"] = {
                "ready": prev_instances,
                "starting": current_instances - prev_instances,
                "stopped": status.get("instances", {}).get("stopped", 0)
            }
            mesh["status"]["stable"] = False

        else:
            # Scale down (but not to 0)
            conditions.append({
                "type": "Scaling",
                "status": "True",
                "message": f"Scaling down from {prev_instances} to {current_instances} instances"
            })
            mesh["status"]["instances"] = {
                "ready": prev_instances,
                "starting": 0,
                "stopped": status.get("instances", {}).get("stopped", 0)
            }
            mesh["status"]["stable"] = False

        mesh["status"]["state"] = "Running"

    else:
        # No instance change - steady state
        mesh["status"]["state"] = "Running" if current_instances > 0 else "Stopped"
        mesh["status"]["instances"] = {
            "ready": current_instances,
            "starting": 0,
            "stopped": status.get("instances", {}).get("stopped", 0)
        }
        mesh["status"]["stable"] = True

    mesh["status"]["conditions"] = conditions

    return mesh


def create_mesh(data: Dict) -> Dict:
    """Create a new mesh."""
    # Validate
    errors = validate_mesh_on_create(data)
    if errors:
        raise ValidationErrorCollection(errors)

    name = data["metadata"]["name"]

    # Check for existing mesh
    if name in _MESHES:
        raise ValidationErrorCollection([ValidationError(
            field="metadata.name",
            type=ErrorType.INVALID.value,
            message=f"mesh '{name}' already exists"
        )])

    # Set default replication factor if not specified
    spec = data.get("spec", {})
    network = spec.get("network", {})
    instances = spec.get("instances", 1)

    if network.get("replicationFactor") is None:
        if "network" not in spec:
            spec["network"] = {}
        spec["network"]["replicationFactor"] = compute_replication_factor_default(instances)

    # Set default storage size if not specified
    storage = network.get("storage", {})
    if storage.get("size") is None:
        if "storage" not in network:
            network["storage"] = {}
        network["storage"]["size"] = "1Gi"

    # Create mesh with initial status
    mesh = {
        "apiVersion": "mesh.example.com/v1",
        "kind": "Mesh",
        "metadata": data.get("metadata", {}),
        "spec": spec,
        "status": {
            "state": "Running",
            "stable": True,
            "instances": {
                "ready": instances,
                "starting": 0,
                "stopped": 0
            },
            "conditions": [
                {
                    "type": "Healthy",
                    "status": "True",
                    "message": ""
                },
                {
                    "type": "PrechecksPassed",
                    "status": "True",
                    "message": ""
                }
            ]
        }
    }

    # Handle scale down to 0 case
    if instances == 0:
        mesh["status"]["state"] = "Stopped"
        mesh["status"]["desiredInstancesOnResume"] = 0

    _MESHES[name] = mesh

    # Handle instance lifecycle for initial state
    mesh = handle_instance_lifecycle(mesh)
    _MESHES[name] = mesh

    return mesh


def list_meshes() -> List[Dict]:
    """List all mesh summaries."""
    result = []
    for name, mesh in _MESHES.items():
        summary = {
            "metadata": mesh.get("metadata", {}),
            "spec": mesh.get("spec", {}),
            "status": {
                "state": mesh.get("status", {}).get("state"),
                "stable": mesh.get("status", {}).get("stable"),
                "instances": mesh.get("status", {}).get("instances"),
            }
        }
        result.append(summary)
    return result


def describe_mesh(name: str) -> Dict:
    """Describe a specific mesh."""
    if name not in _MESHES:
        return None

    mesh = _MESHES[name].copy()

    # Remove transient conditions on describe
    conditions = mesh.get("status", {}).get("conditions", [])
    conditions = [c for c in conditions if c.get("type") not in ("Scaling", "GracefulShutdown")]

    # Update status to steady state if stable
    if mesh.get("status", {}).get("stable"):
        spec = mesh.get("spec", {})
        status = mesh.get("status", {})
        instances = spec.get("instances", 0)

        # Update ready count to match instances if scaling was happening
        current_ready = status.get("instances", {}).get("ready", 0)
        if instances != current_ready and instances > 0:
            mesh["status"]["instances"] = {
                "ready": instances,
                "starting": 0,
                "stopped": status.get("instances", {}).get("stopped", 0)
            }

    mesh["status"]["conditions"] = conditions

    return mesh


def delete_mesh(name: str) -> bool:
    """Delete a mesh."""
    if name in _MESHES:
        del _MESHES[name]
        return True
    return False


def update_mesh(data: Dict) -> Dict:
    """Update an existing mesh."""
    name = data.get("metadata", {}).get("name")

    if not name:
        raise ValidationErrorCollection([ValidationError(
            field="metadata.name",
            type=ErrorType.NOT_FOUND.value,
            message="metadata.name is required for update"
        )])

    if name not in _MESHES:
        raise ValidationErrorCollection([ValidationError(
            field="metadata.name",
            type=ErrorType.NOT_FOUND.value,
            message=f"mesh '{name}' not found"
        )])

    existing = _MESHES[name]

    # Validate update
    errors = validate_mesh_on_update(existing, data)
    if errors:
        raise ValidationErrorCollection(errors)

    # Merge
    updated = merge_mesh(existing, data)

    # Handle instance lifecycle
    updated = handle_instance_lifecycle(updated)

    _MESHES[name] = updated

    return updated


class ValidationErrorCollection(Exception):
    """Collection of validation errors."""

    def __init__(self, errors: List[ValidationError]):
        self.errors = errors
        super().__init__(self.format_message())

    def format_message(self) -> str:
        if not self.errors:
            return "Validation error"
        error_list = "; ".join([f"{e.field}: {e.type} - {e.message}" for e in self.errors])
        return error_list

    def to_dict(self) -> Dict:
        return {
            "errors": [e.to_dict() for e in self.errors]
        }


def cmd_mesh_create(args: argparse.Namespace) -> int:
    """Handle mesh create command."""
    try:
        data = parse_yaml_file(args.file)
        mesh = create_mesh(data)
        print(json.dumps(mesh, indent=2))
        return 0
    except (FileNotFoundError, ValueError) as e:
        print(f"Error: {e}", file=sys.stderr)
        return 1
    except ValidationErrorCollection as e:
        print(json.dumps(e.to_dict(), indent=2), file=sys.stderr)
        return 1


def cmd_mesh_list(args: argparse.Namespace) -> int:
    """Handle mesh list command."""
    meshes = list_meshes()
    print(json.dumps(meshes, indent=2))
    return 0


def cmd_mesh_describe(args: argparse.Namespace) -> int:
    """Handle mesh describe command."""
    mesh = describe_mesh(args.name)
    if mesh is None:
        error = ValidationErrorCollection([ValidationError(
            field="metadata.name",
            type=ErrorType.NOT_FOUND.value,
            message=f"mesh '{args.name}' not found"
        )])
        print(json.dumps(error.to_dict(), indent=2), file=sys.stderr)
        return 1
    print(json.dumps(mesh, indent=2))
    return 0


def cmd_mesh_delete(args: argparse.Namespace) -> int:
    """Handle mesh delete command."""
    if delete_mesh(args.name):
        print(f"Mesh '{args.name}' deleted")
        return 0
    else:
        error = ValidationErrorCollection([ValidationError(
            field="metadata.name",
            type=ErrorType.NOT_FOUND.value,
            message=f"mesh '{args.name}' not found"
        )])
        print(json.dumps(error.to_dict(), indent=2), file=sys.stderr)
        return 1


def cmd_mesh_update(args: argparse.Namespace) -> int:
    """Handle mesh update command."""
    try:
        data = parse_yaml_file(args.file)
        mesh = update_mesh(data)
        print(json.dumps(mesh, indent=2))
        return 0
    except (FileNotFoundError, ValueError) as e:
        print(f"Error: {e}", file=sys.stderr)
        return 1
    except ValidationErrorCollection as e:
        print(json.dumps(e.to_dict(), indent=2), file=sys.stderr)
        return 1


def main():
    """Main CLI entry point."""
    parser = argparse.ArgumentParser(
        description="Mesh Lifecycle and Topology CLI Tool"
    )
    subparsers = parser.add_subparsers(dest="command", help="Available commands")

    # Mesh subcommands
    mesh_parser = subparsers.add_parser("mesh", help="Mesh operations")
    mesh_subparsers = mesh_parser.add_subparsers(dest="mesh_command", help="Mesh commands")

    # mesh create
    create_parser = mesh_subparsers.add_parser("create", help="Create a mesh from YAML")
    create_parser.add_argument("-f", "--file", required=True, help="Path to YAML file")
    create_parser.set_defaults(func=cmd_mesh_create)

    # mesh list
    list_parser = mesh_subparsers.add_parser("list", help="List mesh summaries")
    list_parser.set_defaults(func=cmd_mesh_list)

    # mesh describe
    describe_parser = mesh_subparsers.add_parser("describe", help="Print the full mesh")
    describe_parser.add_argument("name", help="Mesh name")
    describe_parser.set_defaults(func=cmd_mesh_describe)

    # mesh delete
    delete_parser = mesh_subparsers.add_parser("delete", help="Delete the mesh")
    delete_parser.add_argument("name", help="Mesh name")
    delete_parser.set_defaults(func=cmd_mesh_delete)

    # mesh update
    update_parser = mesh_subparsers.add_parser("update", help="Apply a partial update")
    update_parser.add_argument("-f", "--file", required=True, help="Path to YAML file")
    update_parser.set_defaults(func=cmd_mesh_update)

    args = parser.parse_args()

    if hasattr(args, 'func'):
        return args.func(args)
    else:
        parser.print_help()
        return 1


if __name__ == "__main__":
    sys.exit(main())

