def load_storage() -> Dict[str, Dict]:
    """Load meshes from persistent storage."""
    storage_file = "/tmp/meshes.json"
    if os.path.exists(storage_file):
        with open(storage_file, "r") as f:
            return json.load(f)
    return {}


def save_storage(data: Dict):
